// Validate and insert feedback into Supabase
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const body = $input.first().json.body || $input.first().json;
const { ai_output_id, rating, comment } = body;

// Validation
if (!ai_output_id) {
  return [{ json: { success: false, error: 'ai_output_id is required' } }];
}
if (!rating || !['positive', 'negative'].includes(rating)) {
  return [{ json: { success: false, error: 'rating must be positive or negative' } }];
}

try {
  // Insert feedback
  const feedbackResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/feedback`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({
      ai_output_id,
      rating,
      comment: comment || null
    })
  });

  const feedbackId = Array.isArray(feedbackResponse) && feedbackResponse.length > 0 
    ? feedbackResponse[0].id : null;

  // Log event
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/events`,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=minimal'
    },
    body: JSON.stringify({
      event_type: 'feedback_given',
      payload: { ai_output_id, rating, feedback_id: feedbackId }
    })
  });

  return [{ json: { success: true, data: { feedback_id: feedbackId } } }];
} catch (error) {
  return [{ json: { success: false, error: error.message } }];
}
